//! P1 Tests: Join Flow (AC → GC → MC End-to-End)
//!
//! End-to-end tests validating the full meeting join path across all three services.
//!
//! # Prerequisites
//!
//! - Kind cluster with AC, GC, and MC deployed
//! - Port-forwards active: AC (8082), GC (8080), MC WebTransport (4433)
//! - Test data seeded: `devtest` organization in database
//! - AC_JWKS_URL configured on GC and MC for token validation
//!
//! # TLS Note
//!
//! MC WebTransport uses self-signed dev certs generated by `scripts/generate-dev-certs.sh`.
//! The dev CA is at `infra/docker/certs/ca.crt`. MC tests use
//! `with_no_cert_validation()` (matching the pattern in `mc-service/tests/join_tests.rs`)
//! because the dev CA cert is generated at Kind setup time and not committed to the repo.

#![cfg(feature = "flows")]

use bytes::{BufMut, BytesMut};
use env_tests::cluster::ClusterConnection;
use env_tests::fixtures::auth_client::{TokenRequest, UserRegistrationRequest};
use env_tests::fixtures::gc_client::{CreateMeetingRequest, GcClient, GcClientError};
use env_tests::fixtures::AuthClient;
use prost::Message;
use proto_gen::signaling::{
    client_message, server_message, ClientMessage, JoinRequest, ServerMessage,
};
use std::time::Duration;
use tokio::sync::OnceCell;

// ============================================================================
// Test Infrastructure
// ============================================================================

/// Shared cluster connection (initialized once, reused across all tests).
static CLUSTER: OnceCell<ClusterConnection> = OnceCell::const_new();

/// Shared test user token (reduces registration count within rate limit budget).
/// Tests that only need a valid user JWT reuse this instead of registering their own.
static SHARED_USER: OnceCell<(String, String)> = OnceCell::const_new();

/// Helper to get a cluster connection, verifying AC + GC are available.
///
/// Used by all tests. Does NOT check MC availability — MC tests will fail
/// with a clear error if MC is not reachable.
async fn cluster() -> &'static ClusterConnection {
    CLUSTER
        .get_or_init(|| async {
            let cluster = ClusterConnection::new()
                .await
                .expect("Failed to connect to cluster - ensure port-forwards are running");
            cluster
                .check_ac_health()
                .await
                .expect("AC service must be running for join flow tests");
            cluster
                .check_gc_health()
                .await
                .expect("GC service must be running for join flow tests");
            cluster
        })
        .await
}

/// Get a shared test user token for GC-level tests.
///
/// Returns (access_token, display_name). Registers the user once via AC;
/// subsequent calls return the cached token. This keeps GC-level registration
/// count to 1 instead of 5, staying well within AC's 5/hour rate limit.
async fn shared_user(cluster: &ClusterConnection) -> &'static (String, String) {
    SHARED_USER
        .get_or_init(|| async {
            let auth_client = AuthClient::new(&cluster.ac_base_url);
            register_test_user(&auth_client, "Join Flow Shared User").await
        })
        .await
}

/// Register a test user via AC and return the user JWT access token and display name.
async fn register_test_user(auth_client: &AuthClient, display_name: &str) -> (String, String) {
    let request = UserRegistrationRequest::unique(display_name);
    let display = request.display_name.clone();
    let response = auth_client
        .register_user(&request)
        .await
        .expect("AC should register test user");
    (response.access_token, display)
}

/// Connect a wtransport client to the MC WebTransport endpoint.
///
/// Uses `with_no_cert_validation()` for Kind's self-signed dev certs.
/// Dev CA is generated by `scripts/generate-dev-certs.sh` at Kind setup time
/// and is not available in CI. This matches `mc-service/tests/join_tests.rs`.
async fn connect_mc(url: &str) -> wtransport::Connection {
    let client_config = wtransport::ClientConfig::builder()
        .with_bind_default()
        .with_no_cert_validation()
        .build();

    let client = wtransport::Endpoint::client(client_config).expect("create WebTransport client");
    client
        .connect(url)
        .await
        .expect("connect to MC WebTransport")
}

/// Encode a `ClientMessage` as a length-prefixed frame (4-byte BE length + protobuf).
///
/// Wire format matches MC's `connection.rs` framing protocol.
fn encode_framed(msg: &ClientMessage) -> Vec<u8> {
    let encoded = msg.encode_to_vec();
    let len = encoded.len() as u32;
    let mut frame = BytesMut::with_capacity(4 + encoded.len());
    frame.put_u32(len);
    frame.put_slice(&encoded);
    frame.to_vec()
}

/// Read a length-prefixed `ServerMessage` from a recv stream.
///
/// Returns `None` if the stream is closed or the message is malformed.
async fn read_server_message(recv: &mut wtransport::stream::RecvStream) -> Option<ServerMessage> {
    let mut len_buf = [0u8; 4];
    if recv.read_exact(&mut len_buf).await.is_err() {
        return None;
    }

    let msg_len = u32::from_be_bytes(len_buf) as usize;
    if msg_len == 0 || msg_len > 65536 {
        return None;
    }

    let mut buf = vec![0u8; msg_len];
    if recv.read_exact(&mut buf).await.is_err() {
        return None;
    }

    ServerMessage::decode(buf.as_slice()).ok()
}

/// Send a JoinRequest over a WebTransport bidi stream and read the response.
///
/// Opens a new bidi stream on the connection, sends the framed JoinRequest,
/// and reads the ServerMessage response with a timeout.
async fn send_join_and_read_response(
    conn: &wtransport::Connection,
    meeting_id: &str,
    join_token: &str,
    participant_name: &str,
) -> ServerMessage {
    let (mut send, mut recv) = conn
        .open_bi()
        .await
        .expect("open bi stream")
        .await
        .expect("bi stream ready");

    let client_msg = ClientMessage {
        message: Some(client_message::Message::JoinRequest(JoinRequest {
            meeting_id: meeting_id.to_string(),
            join_token: join_token.to_string(),
            participant_name: participant_name.to_string(),
            capabilities: None,
            correlation_id: String::new(),
            binding_token: String::new(),
        })),
    };

    let frame = encode_framed(&client_msg);
    send.write_all(&frame).await.expect("write JoinRequest");

    tokio::time::timeout(Duration::from_secs(10), async {
        read_server_message(&mut recv)
            .await
            .expect("read server message")
    })
    .await
    .expect("Timeout waiting for MC response")
}

